@@ -0,0 +1,429 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://frankensearch.dev/schemas/fsfs-explanation-payload-v1.schema.json",
+  "title": "fsfs Explanation Payload Contract v1",
+  "oneOf": [
+    {
+      "$ref": "#/$defs/contractDefinition"
+    },
+    {
+      "$ref": "#/$defs/explanationDecision"
+    }
+  ],
+  "$defs": {
+    "reasonCode": {
+      "type": "string",
+      "pattern": "^[a-z0-9]+\\.[a-z0-9_]+\\.[a-z0-9_.-]+$"
+    },
+    "confidencePerMille": {
+      "type": "integer",
+      "minimum": 0,
+      "maximum": 1000
+    },
+    "scoreComponentSource": {
+      "type": "string",
+      "enum": [
+        "lexical_bm25",
+        "semantic_fast",
+        "semantic_quality",
+        "rerank"
+      ]
+    },
+    "policyDomain": {
+      "type": "string",
+      "enum": [
+        "query_intent",
+        "retrieval_budget",
+        "query_execution",
+        "degradation",
+        "discovery"
+      ]
+    },
+    "rankingPhase": {
+      "type": "string",
+      "enum": [
+        "Initial",
+        "Refined"
+      ]
+    },
+    "traceLink": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "trace_id",
+        "event_id"
+      ],
+      "properties": {
+        "trace_id": {
+          "type": "string",
+          "minLength": 1
+        },
+        "event_id": {
+          "type": "string",
+          "minLength": 1
+        },
+        "parent_event_id": {
+          "type": "string",
+          "minLength": 1
+        },
+        "claim_id": {
+          "type": "string",
+          "minLength": 1
+        },
+        "policy_id": {
+          "type": "string",
+          "minLength": 1
+        }
+      }
+    },
+    "rankMovementSnapshot": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "initial_rank",
+        "refined_rank",
+        "delta",
+        "reason"
+      ],
+      "properties": {
+        "initial_rank": {
+          "type": "integer",
+          "minimum": 0
+        },
+        "refined_rank": {
+          "type": "integer",
+          "minimum": 0
+        },
+        "delta": {
+          "type": "integer"
+        },
+        "reason": {
+          "type": "string",
+          "minLength": 1
+        }
+      }
+    },
+    "fusionContext": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "fused_score",
+        "in_both_sources"
+      ],
+      "properties": {
+        "fused_score": {
+          "type": "number"
+        },
+        "lexical_rank": {
+          "type": "integer",
+          "minimum": 0
+        },
+        "semantic_rank": {
+          "type": "integer",
+          "minimum": 0
+        },
+        "lexical_score": {
+          "type": "number"
+        },
+        "semantic_score": {
+          "type": "number"
+        },
+        "in_both_sources": {
+          "type": "boolean"
+        }
+      }
+    },
+    "scoreComponentBreakdown": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "source",
+        "summary",
+        "raw_score",
+        "normalized_score",
+        "rrf_contribution",
+        "weight",
+        "confidence_per_mille"
+      ],
+      "properties": {
+        "source": {
+          "$ref": "#/$defs/scoreComponentSource"
+        },
+        "summary": {
+          "type": "string",
+          "minLength": 1
+        },
+        "raw_score": {
+          "type": "number"
+        },
+        "normalized_score": {
+          "type": "number"
+        },
+        "rrf_contribution": {
+          "type": "number"
+        },
+        "weight": {
+          "type": "number",
+          "minimum": 0
+        },
+        "confidence_per_mille": {
+          "$ref": "#/$defs/confidencePerMille"
+        }
+      }
+    },
+    "rankingExplanation": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "doc_id",
+        "final_score",
+        "phase",
+        "reason_code",
+        "confidence_per_mille",
+        "components"
+      ],
+      "properties": {
+        "doc_id": {
+          "type": "string",
+          "minLength": 1
+        },
+        "final_score": {
+          "type": "number"
+        },
+        "phase": {
+          "$ref": "#/$defs/rankingPhase"
+        },
+        "reason_code": {
+          "$ref": "#/$defs/reasonCode"
+        },
+        "confidence_per_mille": {
+          "$ref": "#/$defs/confidencePerMille"
+        },
+        "rank_movement": {
+          "$ref": "#/$defs/rankMovementSnapshot"
+        },
+        "fusion": {
+          "$ref": "#/$defs/fusionContext"
+        },
+        "components": {
+          "type": "array",
+          "minItems": 1,
+          "items": {
+            "$ref": "#/$defs/scoreComponentBreakdown"
+          }
+        }
+      }
+    },
+    "policyDecisionExplanation": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "domain",
+        "decision",
+        "reason_code",
+        "confidence_per_mille",
+        "summary",
+        "metadata"
+      ],
+      "properties": {
+        "domain": {
+          "$ref": "#/$defs/policyDomain"
+        },
+        "decision": {
+          "type": "string",
+          "minLength": 1
+        },
+        "reason_code": {
+          "$ref": "#/$defs/reasonCode"
+        },
+        "confidence_per_mille": {
+          "$ref": "#/$defs/confidencePerMille"
+        },
+        "summary": {
+          "type": "string",
+          "minLength": 1
+        },
+        "metadata": {
+          "type": "object",
+          "additionalProperties": {
+            "type": "string"
+          }
+        }
+      }
+    },
+    "contractDefinition": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "kind",
+        "v",
+        "ranking_policy",
+        "policy_decision_policy",
+        "transport_parity_policy",
+        "diagnostics_policy"
+      ],
+      "properties": {
+        "kind": {
+          "type": "string",
+          "const": "fsfs_explanation_payload_contract_definition"
+        },
+        "v": {
+          "type": "integer",
+          "const": 1
+        },
+        "ranking_policy": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "required_fields",
+            "require_component_breakdown",
+            "phase_enum"
+          ],
+          "properties": {
+            "required_fields": {
+              "type": "array",
+              "minItems": 6,
+              "items": {
+                "type": "string"
+              }
+            },
+            "require_component_breakdown": {
+              "type": "boolean"
+            },
+            "phase_enum": {
+              "type": "array",
+              "minItems": 2,
+              "maxItems": 2,
+              "items": {
+                "type": "string",
+                "enum": [
+                  "Initial",
+                  "Refined"
+                ]
+              }
+            }
+          }
+        },
+        "policy_decision_policy": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "required_fields",
+            "domain_enum"
+          ],
+          "properties": {
+            "required_fields": {
+              "type": "array",
+              "minItems": 6,
+              "items": {
+                "type": "string"
+              }
+            },
+            "domain_enum": {
+              "type": "array",
+              "minItems": 5,
+              "maxItems": 5,
+              "items": {
+                "$ref": "#/$defs/policyDomain"
+              }
+            }
+          }
+        },
+        "transport_parity_policy": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "json_lossless",
+            "toon_requires_stable_labels",
+            "tui_preserves_reason_codes"
+          ],
+          "properties": {
+            "json_lossless": {
+              "type": "boolean"
+            },
+            "toon_requires_stable_labels": {
+              "type": "boolean"
+            },
+            "tui_preserves_reason_codes": {
+              "type": "boolean"
+            }
+          }
+        },
+        "diagnostics_policy": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "reason_code_prefixes",
+            "confidence_bounds"
+          ],
+          "properties": {
+            "reason_code_prefixes": {
+              "type": "array",
+              "minItems": 2,
+              "items": {
+                "type": "string"
+              }
+            },
+            "confidence_bounds": {
+              "type": "array",
+              "prefixItems": [
+                {
+                  "type": "integer",
+                  "const": 0
+                },
+                {
+                  "type": "integer",
+                  "const": 1000
+                }
+              ],
+              "minItems": 2,
+              "maxItems": 2
+            }
+          }
+        }
+      }
+    },
+    "explanationDecision": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "kind",
+        "v",
+        "schema_version",
+        "query",
+        "ranking",
+        "policy_decisions"
+      ],
+      "properties": {
+        "kind": {
+          "type": "string",
+          "const": "fsfs_explanation_payload_decision"
+        },
+        "v": {
+          "type": "integer",
+          "const": 1
+        },
+        "schema_version": {
+          "type": "string",
+          "const": "fsfs.explanation.payload.v1"
+        },
+        "query": {
+          "type": "string",
+          "minLength": 1
+        },
+        "trace": {
+          "$ref": "#/$defs/traceLink"
+        },
+        "ranking": {
+          "$ref": "#/$defs/rankingExplanation"
+        },
+        "policy_decisions": {
+          "type": "array",
+          "items": {
+            "$ref": "#/$defs/policyDecisionExplanation"
+          }
+        }
+      }
+    }
+  }
+}

@@ -0,0 +1,374 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://frankensearch.dev/schemas/fsfs-pressure-profiles-v1.schema.json",
+  "title": "fsfs Pressure Profiles Contract v1",
+  "oneOf": [
+    {
+      "$ref": "#/$defs/contractDefinition"
+    },
+    {
+      "$ref": "#/$defs/profileResolution"
+    }
+  ],
+  "$defs": {
+    "profileId": {
+      "type": "string",
+      "enum": [
+        "strict",
+        "performance",
+        "degraded"
+      ]
+    },
+    "reasonCode": {
+      "type": "string",
+      "pattern": "^(profile|override|safety)\\.[a-z0-9_.-]+$"
+    },
+    "schedulerMode": {
+      "type": "string",
+      "enum": [
+        "fair_share",
+        "latency_sensitive"
+      ]
+    },
+    "fieldName": {
+      "type": "string",
+      "enum": [
+        "scheduler_mode",
+        "max_embed_concurrency",
+        "max_index_concurrency",
+        "quality_enabled",
+        "allow_background_indexing"
+      ]
+    },
+    "profileConfig": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "scheduler_mode",
+        "max_embed_concurrency",
+        "max_index_concurrency",
+        "quality_enabled",
+        "allow_background_indexing",
+        "pressure_enter_threshold",
+        "pressure_exit_threshold",
+        "override_policy"
+      ],
+      "properties": {
+        "scheduler_mode": {
+          "$ref": "#/$defs/schedulerMode"
+        },
+        "max_embed_concurrency": {
+          "type": "integer",
+          "minimum": 1,
+          "maximum": 64
+        },
+        "max_index_concurrency": {
+          "type": "integer",
+          "minimum": 1,
+          "maximum": 64
+        },
+        "quality_enabled": {
+          "type": "boolean"
+        },
+        "allow_background_indexing": {
+          "type": "boolean"
+        },
+        "pressure_enter_threshold": {
+          "type": "number",
+          "minimum": 0,
+          "maximum": 1
+        },
+        "pressure_exit_threshold": {
+          "type": "number",
+          "minimum": 0,
+          "maximum": 1
+        },
+        "override_policy": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "overridable_fields",
+            "locked_fields"
+          ],
+          "properties": {
+            "overridable_fields": {
+              "type": "array",
+              "items": {
+                "$ref": "#/$defs/fieldName"
+              },
+              "uniqueItems": true
+            },
+            "locked_fields": {
+              "type": "array",
+              "items": {
+                "$ref": "#/$defs/fieldName"
+              },
+              "uniqueItems": true
+            }
+          }
+        }
+      }
+    },
+    "contractDefinition": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "kind",
+        "v",
+        "profiles",
+        "precedence_order",
+        "migration_policy"
+      ],
+      "properties": {
+        "kind": {
+          "type": "string",
+          "const": "fsfs_pressure_profiles_contract_definition"
+        },
+        "v": {
+          "type": "integer",
+          "const": 1
+        },
+        "profiles": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "strict",
+            "performance",
+            "degraded"
+          ],
+          "properties": {
+            "strict": {
+              "$ref": "#/$defs/profileConfig"
+            },
+            "performance": {
+              "$ref": "#/$defs/profileConfig"
+            },
+            "degraded": {
+              "$ref": "#/$defs/profileConfig"
+            }
+          }
+        },
+        "precedence_order": {
+          "type": "array",
+          "prefixItems": [
+            {
+              "const": "hard_safety_guards"
+            },
+            {
+              "const": "cli_override"
+            },
+            {
+              "const": "env_override"
+            },
+            {
+              "const": "config_override"
+            },
+            {
+              "const": "profile_default"
+            }
+          ],
+          "items": {
+            "type": "string"
+          },
+          "minItems": 5
+        },
+        "migration_policy": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "profile_version",
+            "requires_revision_bump_on_semantic_change",
+            "drift_protection"
+          ],
+          "properties": {
+            "profile_version": {
+              "type": "integer",
+              "minimum": 1
+            },
+            "requires_revision_bump_on_semantic_change": {
+              "type": "boolean",
+              "const": true
+            },
+            "drift_protection": {
+              "type": "string",
+              "enum": [
+                "explicit_migration_required",
+                "compat_layer_with_reason_code"
+              ]
+            },
+            "deprecated_fields": {
+              "type": "array",
+              "items": {
+                "type": "string",
+                "minLength": 1
+              },
+              "uniqueItems": true
+            }
+          }
+        }
+      }
+    },
+    "overrideDecision": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "field",
+        "source",
+        "requested_value",
+        "applied",
+        "reason_code"
+      ],
+      "properties": {
+        "field": {
+          "$ref": "#/$defs/fieldName"
+        },
+        "source": {
+          "type": "string",
+          "enum": [
+            "cli",
+            "env",
+            "config"
+          ]
+        },
+        "requested_value": {},
+        "applied": {
+          "type": "boolean"
+        },
+        "reason_code": {
+          "$ref": "#/$defs/reasonCode"
+        }
+      }
+    },
+    "profileResolution": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "kind",
+        "v",
+        "trace_id",
+        "selected_profile",
+        "overrides",
+        "effective",
+        "safety_clamps",
+        "conflict_detected",
+        "diagnostics"
+      ],
+      "properties": {
+        "kind": {
+          "type": "string",
+          "const": "fsfs_pressure_profile_resolution"
+        },
+        "v": {
+          "type": "integer",
+          "const": 1
+        },
+        "trace_id": {
+          "type": "string",
+          "minLength": 1
+        },
+        "selected_profile": {
+          "$ref": "#/$defs/profileId"
+        },
+        "overrides": {
+          "type": "array",
+          "items": {
+            "$ref": "#/$defs/overrideDecision"
+          }
+        },
+        "effective": {
+          "$ref": "#/$defs/profileConfig"
+        },
+        "safety_clamps": {
+          "type": "array",
+          "items": {
+            "type": "object",
+            "additionalProperties": false,
+            "required": [
+              "field",
+              "clamped_to",
+              "reason_code"
+            ],
+            "properties": {
+              "field": {
+                "$ref": "#/$defs/fieldName"
+              },
+              "clamped_to": {},
+              "reason_code": {
+                "$ref": "#/$defs/reasonCode"
+              }
+            }
+          }
+        },
+        "conflict_detected": {
+          "type": "boolean"
+        },
+        "conflict_reason_code": {
+          "$ref": "#/$defs/reasonCode"
+        },
+        "diagnostics": {
+          "type": "object",
+          "additionalProperties": false,
+          "required": [
+            "event",
+            "reason_code",
+            "precedence_chain",
+            "effective_profile_version"
+          ],
+          "properties": {
+            "event": {
+              "type": "string",
+              "minLength": 1
+            },
+            "reason_code": {
+              "$ref": "#/$defs/reasonCode"
+            },
+            "precedence_chain": {
+              "type": "array",
+              "prefixItems": [
+                {
+                  "const": "hard_safety_guards"
+                },
+                {
+                  "const": "cli_override"
+                },
+                {
+                  "const": "env_override"
+                },
+                {
+                  "const": "config_override"
+                },
+                {
+                  "const": "profile_default"
+                }
+              ],
+              "items": {
+                "type": "string"
+              },
+              "minItems": 5
+            },
+            "effective_profile_version": {
+              "type": "integer",
+              "minimum": 1
+            }
+          }
+        }
+      },
+      "allOf": [
+        {
+          "if": {
+            "properties": {
+              "conflict_detected": {
+                "const": true
+              }
+            }
+          },
+          "then": {
+            "required": [
+              "conflict_reason_code"
+            ]
+          }
+        }
+      ]
+    }
+  }
+}

@@ -0,0 +1,566 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://frankensearch.dev/schemas/fsfs-snippet-highlight-provenance-v1.schema.json",
+  "title": "fsfs Snippet/Highlight/Provenance Contract v1",
+  "oneOf": [
+    {
+      "$ref": "#/$defs/contractDefinition"
+    },
+    {
+      "$ref": "#/$defs/renderDecision"
+    }
+  ],
+  "$defs": {
+    "reasonCode": {
+      "type": "string",
+      "pattern": "^(snippet|highlight|provenance)\\.[a-z0-9_.-]+$"
+    },
+    "sha256Digest": {
+      "type": "string",
+      "pattern": "^sha256:[0-9a-f]{64}$"
+    },
+    "lineRange": {
+      "type": "array",
+      "prefixItems": [
+        {
+          "type": "integer",
+          "minimum": 1
+        },
+        {
+          "type": "integer",
+          "minimum": 1
+        }
+      ],
+      "minItems": 2,
+      "maxItems": 2
+    },
+    "byteRange": {
+      "type": "array",
+      "prefixItems": [
+        {
+          "type": "integer",
+          "minimum": 0
+        },
+        {
+          "type": "integer",
+          "minimum": 0
+        }
+      ],
+      "minItems": 2,
+      "maxItems": 2
+    },
+    "scoreContributor": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "name",
+        "weight",
+        "raw_score"
+      ],
+      "properties": {
+        "name": {
+          "type": "string",
+          "minLength": 1
+        },
+        "weight": {
+          "type": "number",
+          "minimum": 0
+        },
+        "raw_score": {
+          "type": "number"
+        }
+      }
+    },
+    "highlightRange": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "start_byte",
+        "end_byte",
+        "highlight_type"
+      ],
+      "properties": {
+        "start_byte": {
+          "type": "integer",
+          "minimum": 0
+        },
+        "end_byte": {
+          "type": "integer",
+          "minimum": 1
+        },
+        "highlight_type": {
+          "type": "string",
+          "enum": [
+            "lexical",
+            "semantic",
+            "fallback",
+            "policy"
+          ]
+        },
+        "query_term": {
+          "type": "string"
+        }
+      }
+    },
+    "snippetSegment": {
+      "type": "object",
+      "additionalProperties": false,
+      "required": [
+        "segment_id",
+        "text",
+        "line_range",
+        "byte_range",
+        "truncated",
+        "highlights"
+      ],
+      "properties": {
+        "segment_id": {
+          "type": "string",
+          "pattern": "^[a-z0-9._-]+$"
+        },
+        "text": {
+          "type": "string"
+        },
+        "line_range": {
+          "$ref": "#/$defs/lineRange"
+        },
+        "byte_range": {
+          "$ref": "#/$defs/byteRange"
